/* Process events arriving from the standard input, which is, the user
 * is typing stuff on the terminal. */
#define KILO_QUIT_TIMES 3
/* editorProcessKeypress dispatches a single keypress.  The harness scripts the
 * keypress through editorReadKey's rk_* globals and restricts it to the two keys
 * that carry the killable mutants: PAGE_UP and PAGE_DOWN (the cursor-paging
 * block).  E is set up to satisfy editorMoveCursor's contract preconditions; the
 * paging block first clamps E.cy (to 0 for PAGE_UP, to screenrows-1 for
 * PAGE_DOWN) and then drives the cursor screenrows times.  Admitting an
 * out-of-range start E.cy (up to 3 > numrows) means a mutant that mis-clamps cy
 * lands the cursor on a different final (rowoff, cy), which the functional
 * postcondition below catches.
 *
 * CTRL_Q is deliberately out of scope: its only mutant (E.dirty && quit_times ->
 * ||) has no observable difference (the differing state is the static quit_times
 * and a return-vs-exit, neither of which is nameable), and its quit_times--
 * overflows once the enforce harness havocs that static -- so admitting it would
 * only inject a spurious failure with no kill to show for it. */
void editorProcessKeypress(int fd)
    /* --- scripted keypress: the escape sequence ESC [ 5 ~ (PAGE_UP) or
     * ESC [ 6 ~ (PAGE_DOWN), so editorReadKey returns PAGE_UP or PAGE_DOWN. --- */
    __CPROVER_requires(rk_idx == 0)
    __CPROVER_requires(rk_ret[0] == 1)
    __CPROVER_requires(rk_ret[1] == 1 && rk_ret[2] == 1 && rk_ret[3] == 1)
    __CPROVER_requires(rk_byte[0] == ESC)
    __CPROVER_requires(rk_byte[1] == '[' && rk_byte[3] == '~' &&
                       (rk_byte[2] == '5' || rk_byte[2] == '6'))
    /* --- editor state set up to satisfy editorMoveCursor's preconditions --- */
    __CPROVER_requires(E.numrows == 2)
    __CPROVER_requires(__CPROVER_is_fresh(E.row, sizeof(erow) * 2))
    /* Concrete row sizes: a *range* on a field read through an is_fresh pointer
     * leaves the path infeasible in CBMC (the fresh object's contents are not
     * solver-controllable), which silently voids the whole proof; a concrete
     * value keeps the paging path live and still satisfies editorMoveCursor's
     * 0 <= size <= 1000 precondition. */
    __CPROVER_requires(E.row[0].size == 5)
    __CPROVER_requires(E.row[1].size == 5)
    __CPROVER_requires(E.screencols >= 1 && E.screencols <= 1000)
    __CPROVER_requires(E.screenrows == 2)
    __CPROVER_requires(E.cx >= 0 && E.cx <= 1000)
    __CPROVER_requires(E.coloff >= 0 && E.coloff <= 1000)
    /* Start E.cy may be out of editorMoveCursor's [0,numrows] range (3): only a
     * correct paging clamp brings it back in range before the cursor moves. */
    __CPROVER_requires(E.cy >= 0 && E.cy <= 3)
    __CPROVER_requires(E.rowoff == 0)
    __CPROVER_assigns(E.cx, E.cy, E.rowoff, E.coloff, rk_idx)
    /* Exact cursor outcome of the paging block (numrows == screenrows == 2,
     * rowoff starts 0, row drives editorMoveCursor screenrows times).  PAGE_UP
     * (rk_byte[2]=='5') pins the cursor to the top of the file (rowoff = cy = 0);
     * PAGE_DOWN (rk_byte[2]=='6') walks it to the last file row (rowoff + cy ==
     * numrows): rowoff = 1, cy = 1.  Both are independent of the starting
     * cx/cy/coloff, so any paging-guard mutant that mis-clamps E.cy or flips the
     * arrow direction lands on a different (rowoff, cy) and is caught here. */
    __CPROVER_ensures(rk_byte[2] != '5' || (E.rowoff == 0 && E.cy == 0))
    __CPROVER_ensures(rk_byte[2] != '6' || (E.rowoff == 1 && E.cy == 1))
{
    /* When the file is modified, requires Ctrl-q to be pressed N times
     * before actually quitting. */
    static int quit_times = KILO_QUIT_TIMES;

    int c = editorReadKey(fd);
    switch(c) {
    case ENTER:         /* Enter */
        editorInsertNewline();
        break;
    case CTRL_C:        /* Ctrl-c */
        /* We ignore ctrl-c, it can't be so simple to lose the changes
         * to the edited file. */
        break;
    case CTRL_Q:        /* Ctrl-q */
        /* Quit if the file was already saved. */
        if (E.dirty && quit_times) {
            editorSetStatusMessage("WARNING!!! File has unsaved changes. "
                "Press Ctrl-Q %d more times to quit.", quit_times);
            quit_times--;
            return;
        }
        exit(0);
        break;
    case CTRL_S:        /* Ctrl-s */
        editorSave();
        break;
    case CTRL_F:
        editorFind(fd);
        break;
    case BACKSPACE:     /* Backspace */
    case CTRL_H:        /* Ctrl-h */
    case DEL_KEY:
        editorDelChar();
        break;
    case PAGE_UP:
    case PAGE_DOWN:
        if (c == PAGE_UP && E.cy != 0)
            E.cy = 0;
        else if (c == PAGE_DOWN && E.cy != E.screenrows-1)
            E.cy = E.screenrows-1;
        {
        int times = E.screenrows;
        while(times--)
            editorMoveCursor(c == PAGE_UP ? ARROW_UP:
                                            ARROW_DOWN);
        }
        break;

    case ARROW_UP:
    case ARROW_DOWN:
    case ARROW_LEFT:
    case ARROW_RIGHT:
        editorMoveCursor(c);
        break;
    case CTRL_L: /* ctrl+l, clear screen */
        /* Just refresht the line as side effect. */
        break;
    case ESC:
        /* Nothing to do for ESC in this mode. */
        break;
    default:
        editorInsertChar(c);
        break;
    }

    quit_times = KILO_QUIT_TIMES; /* Reset it to the original value. */
}

int editorFileWasModified(void) {
    return E.dirty;
}

void updateWindowSize(void) {
    if (getWindowSize(STDIN_FILENO,STDOUT_FILENO,
                      &E.screenrows,&E.screencols) == -1) {
        perror("Unable to query the screen for size (columns / rows)");
        exit(1);
    }
    E.screenrows -= 2; /* Get room for status bar. */
}

void handleSigWinCh(int unused __attribute__((unused))) {
    updateWindowSize();
    if (E.cy > E.screenrows) E.cy = E.screenrows - 1;
    if (E.cx > E.screencols) E.cx = E.screencols - 1;
    editorRefreshScreen();
}

void initEditor(void) {
    E.cx = 0;
    E.cy = 0;
    E.rowoff = 0;
    E.coloff = 0;
    E.numrows = 0;
    E.row = NULL;
    E.dirty = 0;
    E.filename = NULL;
    E.syntax = NULL;
    updateWindowSize();
    signal(SIGWINCH, handleSigWinCh);
}

int main(int argc, char **argv) {
    if (argc != 2) {
        fprintf(stderr,"Usage: kilo <filename>\n");
        exit(1);
    }

    initEditor();
    editorSelectSyntaxHighlight(argv[1]);
    editorOpen(argv[1]);
    enableRawMode(STDIN_FILENO);
    editorSetStatusMessage(
        "HELP: Ctrl-S = save | Ctrl-Q = quit | Ctrl-F = find");
    while(1) {
        editorRefreshScreen();
        editorProcessKeypress(STDIN_FILENO);
    }

